"use client";

import { createContext, useContext, useState, type Dispatch, type ReactNode, type SetStateAction } from "react";

type Theme = "light" | "dark";

type AppContextValue = {
  theme: Theme;
  setTheme: Dispatch<SetStateAction<Theme>>;
};

const AppContext = createContext<AppContextValue | undefined>(undefined);

type AppProviderProps = {
  children: ReactNode;
};

export function AppProvider({ children }: AppProviderProps) {
  const [theme, setTheme] = useState<Theme>("light");

  return <AppContext.Provider value={{ theme, setTheme }}>{children}</AppContext.Provider>;
}

export function useAppContext(): AppContextValue {
  const context = useContext(AppContext);

  if (!context) {
    throw new Error("useAppContext must be used within AppProvider");
  }

  return context;
}

import type { ReactNode } from "react";
import { AppProvider } from "@/components/AppProvider";

type ProvidersProps = {
  children: ReactNode;
};

export function Providers({ children }: ProvidersProps) {
  return <AppProvider>{children}</AppProvider>;
}

export type Post = {
  userId: number;
  id: number;
  title: string;
  body: string;
};

export type Comment = {
  postId: number;
  id: number;
  name: string;
  email: string;
  body: string;
};

const JSON_PLACEHOLDER_BASE_URL = "https://jsonplaceholder.typicode.com";

async function fetchJson<T>(input: string, init?: RequestInit): Promise<T> {
  const response = await fetch(input, init);

  if (!response.ok) {
    throw new Error(`Failed to fetch ${input}: ${response.status}`);
  }

  return (await response.json()) as T;
}

export async function getPosts(limit?: number): Promise<Post[]> {
  const search = typeof limit === "number" ? `?_limit=${limit}` : "";

  return fetchJson<Post[]>(`${JSON_PLACEHOLDER_BASE_URL}/posts${search}`, {
    next: { revalidate: 60 },
  });
}

export async function getPost(id: string): Promise<Post | null> {
  try {
    return await fetchJson<Post>(`${JSON_PLACEHOLDER_BASE_URL}/posts/${id}`, {
      next: { revalidate: 300 },
    });
  } catch {
    return null;
  }
}

export async function getComments(id: string): Promise<Comment[]> {
  return fetchJson<Comment[]>(`${JSON_PLACEHOLDER_BASE_URL}/posts/${id}/comments`, {
    next: { revalidate: 300 },
  });
}

